    const gert::StorageShape *x_storage = context->GetInputShape(0);
    const gert::StorageShape *w_storage = context->GetInputShape(1);
    auto x_origin = x_storage->GetOriginShape();
    auto w_origin = w_storage->GetOriginShape();

    uint32_t n = x_origin.GetDim(0);
    uint32_t c = x_origin.GetDim(1);
    uint32_t h = x_origin.GetDim(2);
    uint32_t w = x_origin.GetDim(3);

    uint32_t kc = w_origin.GetDim(0);
