    // stride index 0
    const int64_t *stride = attrs->GetAttrPointer<int64_t>(0);
    int32_t stride_h = static_cast<int32_t>(stride[0]);
    int32_t stride_w = static_cast<int32_t>(stride[1]);

    // padding index 1
    const int64_t *padding = attrs->GetAttrPointer<int64_t>(1);
    int32_t pad_h = static_cast<int32_t>(padding[0]);
    int32_t pad_w = static_cast<int32_t>(padding[1]);

    // output_padding index 2
    const int64_t *outpad = attrs->GetAttrPointer<int64_t>(2);
    int32_t outpad_h = static_cast<int32_t>(outpad[0]);
    int32_t outpad_w = static_cast<int32_t>(outpad[1]);

    // groups index 3 - scalar int
    const int64_t *groups_ptr = attrs->GetAttrPointer<int64_t>(3);
    int64_t groups_attr = *groups_ptr;
    uint32_t groups = static_cast<uint32_t>(groups_attr);

    // dilation index 4
    const int64_t *dilation = attrs->GetAttrPointer<int64_t>(4);
    int32_t dilation_h = static_cast<int32_t>(dilation[0]);
    int32_t dilation_w = static_cast<int32_t>(dilation[1]);

    // Compute output shape
    uint32_t out_h = (h - 1) * stride_h - 2 * pad_h + dilation_h * (k0 - 1) + outpad_h + 1;
    uint32_t out_w = (w - 1) * stride_w - 2 * pad_w + dilation_w * (k1 - 1) + outpad_w + 1;
    uint32_t out_c = kc * groups;
    uint32_t totalLength = n * out_c * out_h * out_w;

